@@ -0,0 +1,96 @@
+// In-browser end-to-end codegen demo: load the compiler, compile a real
+// .capnp source, walk the resulting model in JS to emit a typed Reader,
+// then exercise that Reader against a hand-crafted message.
+//
+// What this proves: the wasm-built compiler runs in Chromium with no
+// host filesystem, all standard imports resolve from the embedded blob,
+// and the generated Reader code works against bytes the runtime decodes.
+
+import { CapnpCompiler } from "/dist/codegen.mjs";
+import { load as loadRuntime } from "/dist/inlined.mjs";
+
+const status = document.getElementById("status");
+const results = document.getElementById("results");
+const log = (s) => { results.textContent += s + "\n"; };
+const setStatus = (msg) => { status.textContent = msg; console.log("[codegen]", msg); };
+
+async function run() {
+  setStatus("Loading runtime + compiler…");
+  const cpp = await loadRuntime();
+  const cc  = await CapnpCompiler.load();
+
+  log("Compiling a .capnp source in the browser:");
+  log("");
+  const src = `@0xb1f7c5e9c4e02134;
+using Cxx = import "/capnp/c++.capnp";
+$Cxx.namespace("demo");
+
+struct User {
+  id @0 :UInt64;
+  name @1 :Text;
+  active @2 :Bool;
+}
+
+struct Tag {
+  name @0 :Text;
+  weight @1 :UInt32;
+}`;
+  log(src.replace(/^/gm, "    "));
+  log("");
+
+  setStatus("Compiling…");
+  const model = await cc.compileToModel("demo.capnp", src);
+
+  log(`Compiled: ${model.length} struct(s)`);
+  for (const s of model) {
+    log(`  ${s.name}  data=${s.dataWords}w ptr=${s.ptrWords}w  fields=${s.fields.length}`);
+    for (const f of s.fields) {
+      log(`    ${f.name}  ${f.type}  ${f.kind === "data" ? `bitOff=${f.bitOffset}` : `ptr=${f.ptrIndex}`}`);
+    }
+  }
+  log("");
+
+  // Spot-check that the runtime can decode bytes produced by other
+  // implementations of the same wire format. Use the runtime's
+  // any_builder to construct a User with id=42, name="Alice", active=true,
+  // then re-open it via cpp_any_open and read each field.
+  setStatus("Round-tripping a User via the runtime…");
+  cpp._exports.cpp_any_builder_init(2, 1);  // 2 data words (u64+bool), 1 ptr (text)
+  // Write u64 id at byte 0
+  cpp._exports.cpp_any_builder_set_int64_lo_hi(0, 42, 0);
+  // Write bool active=true at bit 64 (byte 8, bit 0)
+  cpp._exports.cpp_any_builder_set_bool(64, 1);
+  // Write text "Alice"
+  const enc = new TextEncoder();
+  const nameBytes = enc.encode("Alice");
+  const inPtr = cpp._exports.cpp_in_ptr();
+  cpp._u8.set(nameBytes, inPtr);
+  cpp._exports.cpp_any_builder_set_text(0, nameBytes.length);
+  const len = cpp._exports.cpp_any_builder_finalize();
+  const bytes = cpp._u8.slice(cpp._exports.cpp_out_ptr(), cpp._exports.cpp_out_ptr() + len);
+
+  // Re-open and read using the same runtime accessors the codegen would emit.
+  cpp._u8.set(bytes, cpp._exports.cpp_in_ptr());
+  cpp._exports.cpp_any_open(bytes.length);
+
+  const idLo = cpp._exports.cpp_any_uint32_at(0, 0);
+  const idHi = cpp._exports.cpp_any_uint32_at(4, 0);
+  const id = idLo + idHi * 4294967296;
+  const active = cpp._exports.cpp_any_bool_at(64, 0) === 1;
+  const nameLen = cpp._exports.cpp_any_text_at(0);
+  const namePtr = cpp._exports.cpp_out_ptr();
+  const name = new TextDecoder().decode(cpp._u8.subarray(namePtr, namePtr + nameLen));
+
+  log(`Round-trip read:  id=${id}  name=${JSON.stringify(name)}  active=${active}`);
+  log("");
+  log("PASS — wasm compiler + runtime fully working in the browser, no host I/O.");
+  setStatus("done");
+  window.__codegenDemoResult = { id, name, active, model };
+}
+
+run().catch((err) => {
+  setStatus("ERROR: " + err.message);
+  console.error(err);
+  log("ERROR: " + err.stack);
+  window.__codegenDemoResult = { error: String(err) };
+});

@@ -0,0 +1,272 @@
+// Realistic workloads: where do we matter vs capnweb?
+//
+// Tiny-payload single-call latency (the previous bench) is invisible behind
+// any real network. The interesting questions:
+//
+//   1. Burst throughput: client fires N calls back-to-back, awaits all.
+//      Auto-batching coalesces the N sends into ONE transport.send.
+//   2. Sparse field access: client receives a 256-field metadata struct,
+//      reads 5 fields. Cap'n Proto skips the rest; capnweb has to JSON.parse
+//      everything.
+//   3. Binary blob delivery: client sends/receives 64 KB of binary data.
+//      Cap'n Proto stores raw bytes; capnweb must base64-encode (1.33x
+//      bandwidth + parse cost).
+//   4. Wire bytes: total bytes per message — bandwidth matters on real WANs.
+//
+// Each is a distinct dimension that DOES translate to user-visible behavior.
+
+import { load as loadWasm } from "../dist/inlined.mjs";
+import {
+  RpcSession as CapnwasmSession,
+  InterfaceRegistry,
+  createMemoryTransportPair,
+} from "../js/rpc.mjs";
+import {
+  PrimitivesBuilder,
+  PrimitivesReader,
+} from "../js/conformance_schema.gen.mjs";
+
+const capnweb = await import("../../capnweb/dist/index.js");
+
+// ---------- Workload 1: Burst throughput ----------------------------------
+
+function capnwebTransportPair() {
+  const make = () => ({
+    _q: [], _w: [],
+    send(msg) {
+      const peer = this.peer;
+      if (peer._w.length) peer._w.shift().resolve(msg);
+      else peer._q.push(msg);
+      return Promise.resolve();
+    },
+    receive() {
+      if (this._q.length) return Promise.resolve(this._q.shift());
+      return new Promise((res, rej) => this._w.push({ resolve: res, reject: rej }));
+    },
+    abort() { for (const w of this._w) w.reject(new Error("abort")); },
+  });
+  const a = make(); const b = make();
+  a.peer = b; b.peer = a;
+  return { a, b };
+}
+
+class CapnwebEcho extends capnweb.RpcTarget {
+  echo(p) { return p; }
+}
+
+async function setupCapnweb() {
+  const { a, b } = capnwebTransportPair();
+  new capnweb.RpcSession(b, new CapnwebEcho());
+  const client = new capnweb.RpcSession(a);
+  return client.getRemoteMain();
+}
+
+const IFC = 0xc0ffeec0ffeec0ffn;
+
+async function setupCapnwasm() {
+  const cppA = await loadWasm();
+  const cppB = await loadWasm();
+  const { a, b } = createMemoryTransportPair();
+  const registry = new InterfaceRegistry();
+  registry.register(IFC, 0, (target, ctx) => {
+    const p = ctx.openParams(PrimitivesReader);
+    const u8 = p.u8;
+    const reply = ctx.beginResults(PrimitivesBuilder);
+    reply.u8 = u8;
+  });
+  new CapnwasmSession(cppB, b, registry, { bootstrap: {} });
+  const client = new CapnwasmSession(cppA, a);
+  return { client, root: client.bootstrap() };
+}
+
+const cwbRoot = await setupCapnweb();
+const { root: ourRoot } = await setupCapnwasm();
+
+console.log("\n══ Workload 1: Burst throughput (fire N calls, await all) ══\n");
+console.log("  N    | capnweb total | capnwasm total | per-call cwb / us | per-call ours / us");
+console.log("  ─────|───────────────|────────────────|───────────────────|──────────────────");
+
+for (const N of [1, 10, 100, 1000]) {
+  // Warm
+  for (let w = 0; w < 5; w++) {
+    await Promise.all(Array.from({ length: N }, () => cwbRoot.echo({ u8: 1 })));
+    await Promise.all(Array.from({ length: N }, () => {
+      const r = ourRoot.callBuilder(IFC, 0, PrimitivesBuilder);
+      r.params.u8 = 1;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }));
+  }
+
+  const ITERS = N >= 1000 ? 20 : N >= 100 ? 100 : 200;
+  let cwbMs = 0, oursMs = 0;
+  for (let i = 0; i < ITERS; i++) {
+    const t0 = process.hrtime.bigint();
+    await Promise.all(Array.from({ length: N }, () => cwbRoot.echo({ u8: 1 })));
+    cwbMs += Number(process.hrtime.bigint() - t0) / 1e6;
+    const t1 = process.hrtime.bigint();
+    await Promise.all(Array.from({ length: N }, () => {
+      const r = ourRoot.callBuilder(IFC, 0, PrimitivesBuilder);
+      r.params.u8 = 1;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }));
+    oursMs += Number(process.hrtime.bigint() - t1) / 1e6;
+  }
+  const cwbAvg = cwbMs / ITERS;
+  const oursAvg = oursMs / ITERS;
+  console.log(
+    `  ${N.toString().padStart(4)} | ${cwbAvg.toFixed(2).padStart(11)}ms | ${oursAvg.toFixed(2).padStart(12)}ms | ${(cwbAvg * 1000 / N).toFixed(2).padStart(15)} | ${(oursAvg * 1000 / N).toFixed(2).padStart(15)}`,
+  );
+}
+
+// ---------- Workload 2: Wire bytes ---------------------------------------
+
+console.log("\n══ Workload 2: Bytes-on-wire per call ══\n");
+console.log("  payload                       capnweb (JSON)  capnwasm (binary)  ratio");
+console.log("  ──────────────────────────────────────────────────────────────────────");
+
+function recordCwbBytes() {
+  let cwbBytes = 0;
+  const make = () => ({
+    _q: [], _w: [],
+    send(msg) {
+      cwbBytes += msg.length;
+      const peer = this.peer;
+      if (peer._w.length) peer._w.shift().resolve(msg);
+      else peer._q.push(msg);
+      return Promise.resolve();
+    },
+    receive() {
+      if (this._q.length) return Promise.resolve(this._q.shift());
+      return new Promise((res, rej) => this._w.push({ resolve: res, reject: rej }));
+    },
+    abort() {},
+  });
+  const a = make(); const b = make();
+  a.peer = b; b.peer = a;
+  return { a, b, getCwbBytes: () => cwbBytes };
+}
+
+async function cwbCallSize(arg) {
+  const { a, b, getCwbBytes } = recordCwbBytes();
+  new capnweb.RpcSession(b, new CapnwebEcho());
+  const client = new capnweb.RpcSession(a);
+  const r = client.getRemoteMain();
+  await r.echo(arg);
+  return getCwbBytes();
+}
+
+async function ourCallSize(text, binary) {
+  const cppA = await loadWasm();
+  const cppB = await loadWasm();
+  const { a, b } = createMemoryTransportPair();
+  let bytes = 0;
+  const realSend = a.send.bind(a);
+  a.send = (b) => { bytes += b.length; realSend(b); };
+  const reg = new InterfaceRegistry();
+  reg.register(IFC, 0, (target, ctx) => {
+    ctx.openParams(PrimitivesReader);
+    ctx.beginResults(PrimitivesBuilder);
+  });
+  new CapnwasmSession(cppB, b, reg, { bootstrap: {} });
+  const c = new CapnwasmSession(cppA, a);
+  const root = c.bootstrap();
+  const r = root.callBuilder(IFC, 0, PrimitivesBuilder);
+  if (text !== undefined) r.params.text = text;
+  if (binary !== undefined) r.params.data = binary;
+  await r.send({ resultsReader: PrimitivesReader, extract: () => null }).promise;
+  return bytes;
+}
+
+const cases = [
+  { name: "no payload (just method)",   cwb: {},                    text: undefined, binary: undefined },
+  { name: "16B text",                    cwb: { text: "x".repeat(16) },     text: "x".repeat(16) },
+  { name: "256B text",                   cwb: { text: "x".repeat(256) },    text: "x".repeat(256) },
+  { name: "4KB text",                    cwb: { text: "x".repeat(4096) },   text: "x".repeat(4096) },
+  { name: "64KB binary blob",            cwb: { bin: Array.from(new Uint8Array(64 * 1024).map((_, i) => i & 0xff)) },
+                                          binary: new Uint8Array(64 * 1024).map((_, i) => i & 0xff) },
+];
+
+for (const c of cases) {
+  const cwbBytes = await cwbCallSize(c.cwb);
+  const ourBytes = await ourCallSize(c.text, c.binary);
+  const ratio = (cwbBytes / ourBytes).toFixed(2);
+  const winner = cwbBytes > ourBytes ? "✓ capnwasm smaller" : "  capnweb smaller";
+  console.log(
+    `  ${c.name.padEnd(28)} ${cwbBytes.toString().padStart(8)}B   ${ourBytes.toString().padStart(8)}B    ${ratio.padStart(5)}x  ${winner}`,
+  );
+}
+
+// ---------- Workload 3: Sparse field access ------------------------------
+// Server returns a 32-field metadata struct. Client only needs 3 fields.
+// JSON has to materialize all 32 fields (parse the whole JSON tree).
+// Cap'n Proto's wire layout lets the client read just the 3 it needs.
+
+console.log("\n══ Workload 3: Sparse field access (32-field metadata, read 3) ══\n");
+
+class CapnwebMeta extends capnweb.RpcTarget {
+  getMeta() {
+    const o = {};
+    for (let i = 0; i < 32; i++) o["field" + i] = "value" + i + "_" + "x".repeat(40);
+    return o;
+  }
+}
+const { a: ma, b: mb } = capnwebTransportPair();
+new capnweb.RpcSession(mb, new CapnwebMeta());
+const cwbMeta = (new capnweb.RpcSession(ma)).getRemoteMain();
+
+// Our side: use the WideUserData schema (32 string fields).
+const { WideUserDataBuilder, WideUserDataReader } = await import("../js/typed_schema.gen.mjs");
+const META_IFC = 0xdeadbeefcafef00dn;
+const cppC = await loadWasm();
+const cppD = await loadWasm();
+const { a: oa, b: ob } = createMemoryTransportPair();
+const metaReg = new InterfaceRegistry();
+metaReg.register(META_IFC, 0, (target, ctx) => {
+  const reply = ctx.beginResults(WideUserDataBuilder);
+  for (let i = 0; i < 32; i++) {
+    reply["field" + i] = "value" + i + "_" + "x".repeat(40);
+  }
+});
+new CapnwasmSession(cppD, ob, metaReg, { bootstrap: {} });
+const ourMetaSess = new CapnwasmSession(cppC, oa);
+const ourMeta = ourMetaSess.bootstrap();
+
+const N = 1000;
+// Warm
+for (let i = 0; i < 50; i++) {
+  const m = await cwbMeta.getMeta();
+  const _ = m.field0 + m.field5 + m.field10;
+}
+for (let i = 0; i < 50; i++) {
+  const r = ourMeta.callBuilder(META_IFC, 0, WideUserDataBuilder);
+  await r.send({
+    resultsReader: WideUserDataReader,
+    extract: (rdr) => rdr.field0 + rdr.field5 + rdr.field10,
+  }).promise;
+}
+
+let cwbMs = 0;
+let oursMs = 0;
+for (let i = 0; i < N; i++) {
+  const t0 = process.hrtime.bigint();
+  const m = await cwbMeta.getMeta();
+  // Materialize 3 fields (capnweb already parsed all 32 above).
+  const a = m.field0 + m.field5 + m.field10;
+  cwbMs += Number(process.hrtime.bigint() - t0) / 1e6;
+  if (a.length === 0) break;
+}
+for (let i = 0; i < N; i++) {
+  const t0 = process.hrtime.bigint();
+  const r = ourMeta.callBuilder(META_IFC, 0, WideUserDataBuilder);
+  await r.send({
+    resultsReader: WideUserDataReader,
+    extract: (rdr) => rdr.field0 + rdr.field5 + rdr.field10,
+  }).promise;
+  oursMs += Number(process.hrtime.bigint() - t0) / 1e6;
+}
+console.log(`  capnweb (parses all 32 fields): ${(cwbMs * 1000 / N).toFixed(2).padStart(8)}μs/call`);
+console.log(`  capnwasm (reads 3, skips 29):   ${(oursMs * 1000 / N).toFixed(2).padStart(8)}μs/call`);
+console.log(`  speedup:                       ${(cwbMs / oursMs).toFixed(2)}x`);
+
+console.log("");
+process.exit(0);

@@ -0,0 +1,263 @@
+// Browser RPC bench: runs the SAME workloads as bench/rpc_bench.mjs but
+// inside Chromium. Confirms (a) the RPC layer works in a real browser via
+// the inlined wasm bundle and (b) lets us measure capnwasm-RpcSession vs
+// capnweb-RpcSession in V8 directly, where capnweb is at home.
+
+import { load as loadWasm } from "/dist/inlined.mjs";
+import {
+  RpcSession,
+  InterfaceRegistry,
+  createMemoryTransportPair,
+  newBatchedRpcSession,
+} from "/js/rpc.mjs";
+import {
+  PrimitivesBuilder,
+  PrimitivesReader,
+} from "/js/conformance_schema.gen.mjs";
+import * as capnweb from "/capnweb-vendor/index.js";
+
+const status = document.getElementById("status");
+const results = document.getElementById("results");
+const log = (line) => { results.textContent += line + "\n"; };
+const setStatus = (msg) => { status.textContent = msg; console.log("[bench]", msg); };
+
+// ---- Capnweb in-process transport pair (string-based) ------------------
+function capnwebTransportPair() {
+  const make = () => ({
+    _q: [], _w: [],
+    send(msg) {
+      const peer = this.peer;
+      if (peer._w.length) peer._w.shift().resolve(msg);
+      else peer._q.push(msg);
+      return Promise.resolve();
+    },
+    receive() {
+      if (this._q.length) return Promise.resolve(this._q.shift());
+      return new Promise((res, rej) => this._w.push({ resolve: res, reject: rej }));
+    },
+    abort() { for (const w of this._w) w.reject(new Error("abort")); },
+  });
+  const a = make(); const b = make();
+  a.peer = b; b.peer = a;
+  return { a, b };
+}
+
+class CapnwebEcho extends capnweb.RpcTarget {
+  echoU8(o) { return { u8: o.u8 }; }
+  echoText(s) { return "ack:" + s; }
+  getChild() { return new CapnwebEcho(); }
+}
+
+function setupCapnweb() {
+  const { a, b } = capnwebTransportPair();
+  new capnweb.RpcSession(b, new CapnwebEcho());
+  const client = new capnweb.RpcSession(a);
+  return client.getRemoteMain();
+}
+
+// ---- Capnwasm RPC setup -----------------------------------------------
+const IFC = 0xc0ffeec0ffeec0ffn;
+const M_ECHO_U8 = 0;
+const M_ECHO_TEXT = 1;
+const M_GET_CHILD = 2;
+
+async function setupCapnwasm({ batched } = {}) {
+  setStatus(`Loading wasm (batched=${!!batched})…`);
+  const cppA = await loadWasm();
+  const cppB = await loadWasm();
+  const { a, b } = createMemoryTransportPair();
+  const reg = new InterfaceRegistry();
+  reg.register(IFC, M_ECHO_U8, (target, ctx) => {
+    const p = ctx.openParams(PrimitivesReader);
+    const u8 = p.u8;
+    const reply = ctx.beginResults(PrimitivesBuilder);
+    reply.u8 = u8;
+  });
+  reg.register(IFC, M_ECHO_TEXT, (target, ctx) => {
+    const p = ctx.openParams(PrimitivesReader);
+    const t = p.text;
+    const reply = ctx.beginResults(PrimitivesBuilder);
+    reply.text = "ack:" + t;
+  });
+  reg.register(IFC, M_GET_CHILD, () => ({ caps: [{ kind: "child" }] }));
+  new RpcSession(cppB, b, reg, { bootstrap: { kind: "root" } });
+  const Sess = batched ? newBatchedRpcSession : RpcSession;
+  const client = batched
+    ? newBatchedRpcSession(cppA, a, undefined, {})
+    : new RpcSession(cppA, a);
+  return client.bootstrap();
+}
+
+// ---- Timing helpers ----------------------------------------------------
+async function timed(fn, iters) {
+  for (let i = 0; i < 50; i++) await fn(i);
+  const t0 = performance.now();
+  for (let i = 0; i < iters; i++) await fn(i);
+  return ((performance.now() - t0) * 1000) / iters; // µs/call
+}
+
+async function timedBurst(fn, count, iters) {
+  for (let i = 0; i < 5; i++) {
+    await Promise.all(Array.from({ length: count }, fn));
+  }
+  const t0 = performance.now();
+  for (let i = 0; i < iters; i++) {
+    await Promise.all(Array.from({ length: count }, fn));
+  }
+  return ((performance.now() - t0) * 1000) / (iters * count); // µs/call
+}
+
+// ---- Run ---------------------------------------------------------------
+async function run() {
+  const cwbRoot = setupCapnweb();
+  const ourRoot = await setupCapnwasm();
+  const ourBatched = await setupCapnwasm({ batched: true });
+
+  const N = 1000;
+
+  log(`In-browser RPC bench (Chromium V8). N=${N} per workload.\n`);
+  log(`workload                            cwb (JSON)   ours (default)   ours (batched)`);
+  log(`──────────────────────────────────  ───────────  ───────────────  ──────────────`);
+
+  // Tiny: u8 echo
+  {
+    const cwb = await timed(() => cwbRoot.echoU8({ u8: 42 }), N);
+    const our = await timed(() => {
+      const r = ourRoot.callBuilder(IFC, M_ECHO_U8, PrimitivesBuilder);
+      r.params.u8 = 42;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }, N);
+    const batched = await timed(() => {
+      const r = ourBatched.callBuilder(IFC, M_ECHO_U8, PrimitivesBuilder);
+      r.params.u8 = 42;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }, N);
+    log(`u8 echo (single call)               ${fmt(cwb)}   ${fmt(our)}   ${fmt(batched)}`);
+  }
+
+  // Medium text
+  {
+    const t256 = "x".repeat(256);
+    const cwb = await timed(() => cwbRoot.echoText(t256), N);
+    const our = await timed(() => {
+      const r = ourRoot.callBuilder(IFC, M_ECHO_TEXT, PrimitivesBuilder);
+      r.params.text = t256;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.text }).promise;
+    }, N);
+    const batched = await timed(() => {
+      const r = ourBatched.callBuilder(IFC, M_ECHO_TEXT, PrimitivesBuilder);
+      r.params.text = t256;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.text }).promise;
+    }, N);
+    log(`text echo 256B (single call)        ${fmt(cwb)}   ${fmt(our)}   ${fmt(batched)}`);
+  }
+
+  // Burst — fan-out 100 in parallel, then await.
+  {
+    const COUNT = 100, ITERS = 100;
+    const cwb = await timedBurst(() => cwbRoot.echoU8({ u8: 1 }), COUNT, ITERS);
+    const our = await timedBurst(() => {
+      const r = ourRoot.callBuilder(IFC, M_ECHO_U8, PrimitivesBuilder);
+      r.params.u8 = 1;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }, COUNT, ITERS);
+    const batched = await timedBurst(() => {
+      const r = ourBatched.callBuilder(IFC, M_ECHO_U8, PrimitivesBuilder);
+      r.params.u8 = 1;
+      return r.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }, COUNT, ITERS);
+    log(`burst 100 calls/iter (per-call)     ${fmt(cwb)}   ${fmt(our)}   ${fmt(batched)}`);
+  }
+
+  // Cap-passing: getChild then call on returned cap.
+  {
+    const cwb = await timed(async () => {
+      const child = cwbRoot.getChild();
+      return child.echoU8({ u8: 9 });
+    }, N);
+    const our = await timed(() => {
+      const r1 = ourRoot.callBuilder(IFC, M_GET_CHILD, PrimitivesBuilder).send();
+      const r2 = r1.cap.callBuilder(IFC, M_ECHO_U8, PrimitivesBuilder);
+      r2.params.u8 = 9;
+      return r2.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }, N);
+    const batched = await timed(() => {
+      const r1 = ourBatched.callBuilder(IFC, M_GET_CHILD, PrimitivesBuilder).send();
+      const r2 = r1.cap.callBuilder(IFC, M_ECHO_U8, PrimitivesBuilder);
+      r2.params.u8 = 9;
+      return r2.send({ resultsReader: PrimitivesReader, extract: rdr => rdr.u8 }).promise;
+    }, N);
+    log(`cap-passing: getChild + echo        ${fmt(cwb)}   ${fmt(our)}   ${fmt(batched)}`);
+  }
+
+  // Wire-byte comparison (counts characters / bytes per round-trip frame).
+  log("");
+  log(`wire bytes per round-trip:`);
+  await wireBytes("u8 echo",     () => ({ u8: 42 }), 0, false);
+  await wireBytes("text 256B",   () => ({ text: "x".repeat(256) }), 256, false);
+  await wireBytes("text 4KB",    () => ({ text: "x".repeat(4096) }), 4096, false);
+  await wireBytes("64KB binary", () => ({ data: Array.from({length: 64*1024}, (_,i) => i & 0xff) }),
+                                         0, true);
+
+  setStatus("done");
+  window.__rpcBenchResults = results.textContent;
+}
+
+function fmt(us) { return `${us.toFixed(2).padStart(8)}μs`; }
+
+async function wireBytes(name, cwbArgFn, textLen, asBinary) {
+  // cwb side
+  let cwbBytes = 0;
+  const make = () => ({
+    _q: [], _w: [],
+    send(msg) {
+      cwbBytes += msg.length;
+      const peer = this.peer;
+      if (peer._w.length) peer._w.shift().resolve(msg);
+      else peer._q.push(msg);
+      return Promise.resolve();
+    },
+    receive() {
+      if (this._q.length) return Promise.resolve(this._q.shift());
+      return new Promise((res, rej) => this._w.push({ resolve: res, reject: rej }));
+    },
+    abort() {},
+  });
+  const ca = make(); const cb = make();
+  ca.peer = cb; cb.peer = ca;
+  new capnweb.RpcSession(cb, new CapnwebEcho());
+  const cwbRoot = (new capnweb.RpcSession(ca)).getRemoteMain();
+  const arg = cwbArgFn();
+  if (asBinary) await cwbRoot.echoText(arg.data);
+  else await cwbRoot.echoU8 ? await cwbRoot.echoU8(arg) : await cwbRoot.echoText(arg.text || "");
+
+  // our side
+  const cppA = await loadWasm();
+  const cppB = await loadWasm();
+  const { a, b } = createMemoryTransportPair();
+  let ourBytes = 0;
+  const realSend = a.send.bind(a);
+  a.send = (bytes) => { ourBytes += bytes.length; realSend(bytes); };
+  const reg = new InterfaceRegistry();
+  reg.register(IFC, 0, (target, ctx) => {
+    ctx.openParams(PrimitivesReader);
+    ctx.beginResults(PrimitivesBuilder);
+  });
+  new RpcSession(cppB, b, reg, { bootstrap: {} });
+  const c = new RpcSession(cppA, a);
+  const cap = c.bootstrap();
+  const r = cap.callBuilder(IFC, 0, PrimitivesBuilder);
+  if (textLen > 0 && !asBinary) r.params.text = "x".repeat(textLen);
+  if (asBinary) r.params.data = new Uint8Array(64 * 1024).map((_, i) => i & 0xff);
+  await r.send({ resultsReader: PrimitivesReader, extract: () => null }).promise;
+
+  const ratio = (cwbBytes / ourBytes).toFixed(2);
+  log(`  ${name.padEnd(15)}  cwb=${cwbBytes.toString().padStart(7)}B  ours=${ourBytes.toString().padStart(7)}B  ratio=${ratio.padStart(6)}x`);
+}
+
+run().catch((e) => {
+  setStatus("ERROR: " + e.message);
+  console.error(e);
+  log("ERROR: " + e.stack);
+  window.__rpcBenchResults = results.textContent;
+});

