+// JS calls this once per file the compiler may import (including the root).
+// The bytes for `name` are pre-staged in capnpc_in[0..len].
+uint32_t capnpc_add_file(const char* name, uint32_t name_len, uint32_t src_len) {
+  ensureArena();
