+    case W::INT64:   return "Int64";
+    case W::UINT8:   return "UInt8";
+    case W::UINT16:  return "UInt16";
+    case W::UINT32:  return "UInt32";
+    case W::UINT64:  return "UInt64";
+    case W::FLOAT32: return "Float32";
+    case W::FLOAT64: return "Float64";
