+      appendUint(out, sn.getDiscriminantCount());
+      out.addAll(kj::StringPtr(",\"discriminantOffset\":"));
+      appendUint(out, sn.getDiscriminantOffset());  // in u16 units
+    }
+    out.addAll(kj::StringPtr(",\"fields\":["));
+    bool firstField = true;
