+      out.add('{');
+      out.addAll(kj::StringPtr("\"name\":"));
+      appendJsonString(out, f.getName());
+      out.addAll(kj::StringPtr(",\"ordinal\":"));
+      appendUint(out, f.getOrdinal().getExplicit());
+      out.addAll(kj::StringPtr(",\"codeOrder\":"));
+      appendUint(out, f.getCodeOrder());
