+  // Segment table at cpp_out + 4.
+  uint32_t* table = reinterpret_cast<uint32_t*>(cpp_out + 4);
+  table[0] = segCount - 1;
+  for (uint32_t i = 0; i < segCount; i++) {
+    table[i + 1] = static_cast<uint32_t>(segments[i].size());
+  }
+  if (4 * (1 + segCount) != tableBytes) {
+    table[1 + segCount] = 0;
+  }
