+  uint32_t pos = 4 + tableBytes;
+  for (uint32_t i = 0; i < segCount; i++) {
+    auto seg = segments[i];
+    uint32_t segBytes = static_cast<uint32_t>(seg.size() * sizeof(capnp::word));
+    std::memcpy(cpp_out + pos, seg.begin(), segBytes);
+    pos += segBytes;
+  }
