+await writeFile(resolve(ROOT, "dist", "codegen.mjs"), bundle);
+
+const raw = Buffer.byteLength(bundle, "utf8");
+const gz  = gzipSync(bundle, { level: 9 }).length;
+console.log(`dist/codegen.mjs:  raw=${raw}  gzip=${gz}`);

